    codeSolution: "using System;\nusing System.Collections.Generic;\nusing System.Linq;\n\nclass Product\n{\n    public int Id { get; set; }\n    public string Name { get; set; }\n    public decimal Price { get; set; }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        List<Product> products = new List<Product>\n        {\n            new Product { Id = 1, Name = \"Laptop\", Price = 999.99m },\n            new Product { Id = 2, Name = \"Mouse\", Price = 29.99m },\n            new Product { Id = 3, Name = \"Laptop\", Price = 999.99m },\n            new Product { Id = 4, Name = \"Keyboard\", Price = 79.99m }\n        };\n        \n        var distinctByName = products.GroupBy(p => p.Name).Select(g => g.First());\n        Console.WriteLine(\"Distinct by name:\");\n        foreach (var p in distinctByName)\n            Console.WriteLine($\"  {p.Name}\");\n        \n        var numbers = new List<int> { 1, 2, 2, 3, 3, 3, 4, 4, 4, 4 };\n        var unique = numbers.Distinct();\n        Console.WriteLine($\"Unique numbers: {string.Join(\", \", unique)}\");\n    }\n}",
