    question: "Use lambda with Skip and Take for pagination.",
    mathSolution: "list.Skip(10).Take(10)",
    codeSolution: "using System;\nusing System.Collections.Generic;\nusing System.Linq;\n\nclass Program\n{\n    static void Main()\n    {\n        List<int> numbers = Enumerable.Range(1, 100).ToList();\n        \n        int pageSize = 10;\n        int pageNumber = 3;\n        \n        var page = numbers.Skip((pageNumber - 1) * pageSize).Take(pageSize);\n        Console.WriteLine($\"Page {pageNumber}: {string.Join(\", \", page)}\");\n        \n        // TakeWhile\n        var lessThanTwenty = numbers.TakeWhile(n => n < 20);\n        Console.WriteLine($\"TakeWhile (<20): {string.Join(\", \", lessThanTwenty)}\");\n        \n        // SkipWhile\n        var skipUntilFive = numbers.SkipWhile(n => n < 5);\n        Console.WriteLine($\"SkipWhile (<5): {string.Join(\", \", skipUntilFive.Take(10))}...\");\n    }\n}",
