    codeSolution: "using System;\nusing System.Collections.Generic;\nusing System.Linq;\n\nclass Program\n{\n    static void Main()\n    {\n        int[] first = { 1, 2, 3 };\n        int[] second = { 4, 5, 6 };\n        \n        var concatenated = first.Concat(second);\n        Console.WriteLine($\"Concatenated: {string.Join(\", \", concatenated)}\");\n        \n        var withPrepend = first.Prepend(0);\n        Console.WriteLine($\"Prepended 0: {string.Join(\", \", withPrepend)}\");\n        \n        var withAppend = first.Append(4);\n        Console.WriteLine($\"Appended 4: {string.Join(\", \", withAppend)}\");\n        \n        // Chaining\n        var result = first.Append(4).Prepend(0).Concat(second);\n        Console.WriteLine($\"Chained: {string.Join(\", \", result)}\");\n        \n        // Multiple appends/prepends\n        var numbers = new List<int> { 10, 20, 30 };\n        var modified = numbers.Prepend(5).Prepend(1).Append(40).Append(50);\n        Console.WriteLine($\"Multiple operations: {string.Join(\", \", modified)}\");\n    }\n}",
