    question: "Use lambda with ElementAt and ElementAtOrDefault.",
    mathSolution: "list.ElementAt(5)",
    codeSolution: "using System;\nusing System.Collections.Generic;\nusing System.Linq;\n\nclass Program\n{\n    static void Main()\n    {\n        List<int> numbers = new List<int> { 10, 20, 30, 40, 50 };\n        \n        int third = numbers.ElementAt(2);\n        Console.WriteLine($\"Element at index 2: {third}\");\n        \n        int tenth = numbers.ElementAtOrDefault(9);\n        Console.WriteLine($\"Element at index 9 (default): {tenth}\");\n        \n        // With empty list\n        List<int> empty = new List<int>();\n        int defaultValue = empty.ElementAtOrDefault(0);\n        Console.WriteLine($\"Empty list default: {defaultValue}\");\n        \n        try\n        {\n            int invalid = empty.ElementAt(0);\n        }\n        catch (ArgumentOutOfRangeException ex)\n        {\n            Console.WriteLine($\"ElementAt threw: {ex.Message}\");\n        }\n        \n        // Using with Where\n        var evens = numbers.Where(n => n % 2 == 0);\n        int firstEven = evens.ElementAt(0);\n        Console.WriteLine($\"First even: {firstEven}\");\n    }\n}",
