    mathSolution: "from c in customers join o in orders on c.Id equals o.CustomerId",
    codeSolution: "using System;\nusing System.Collections.Generic;\nusing System.Linq;\n\nclass Customer\n{\n    public int Id { get; set; }\n    public string Name { get; set; }\n}\n\nclass Order\n{\n    public int Id { get; set; }\n    public int CustomerId { get; set; }\n    public decimal Amount { get; set; }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        List<Customer> customers = new List<Customer>\n        {\n            new Customer { Id = 1, Name = \"Alice\" },\n            new Customer { Id = 2, Name = \"Bob\" },\n            new Customer { Id = 3, Name = \"Charlie\" }\n        };\n        \n        List<Order> orders = new List<Order>\n        {\n            new Order { Id = 101, CustomerId = 1, Amount = 250.50m },\n            new Order { Id = 102, CustomerId = 1, Amount = 75.25m },\n            new Order { Id = 103, CustomerId = 2, Amount = 199.99m }\n        };\n        \n        var query = from c in customers\n                    join o in orders on c.Id equals o.CustomerId\n                    select new { c.Name, o.Amount };\n        \n        Console.WriteLine(\"Customer Orders:\");\n        foreach (var item in query)\n            Console.WriteLine($\"  {item.Name}: ${item.Amount}\");\n    }\n}",
