    question: "Use LINQ left join (GroupJoin) to include unmatched items.",
    mathSolution: "from c in customers join o in orders on c.Id equals o.CustomerId into gj",
    codeSolution: "using System;\nusing System.Collections.Generic;\nusing System.Linq;\n\nclass Program\n{\n    static void Main()\n    {\n        var customers = new[]\n        {\n            new { Id = 1, Name = \"Alice\" },\n            new { Id = 2, Name = \"Bob\" },\n            new { Id = 3, Name = \"Charlie\" }\n        };\n        \n        var orders = new[]\n        {\n            new { CustomerId = 1, Amount = 250.50m },\n            new { CustomerId = 1, Amount = 75.25m },\n            new { CustomerId = 2, Amount = 199.99m }\n        };\n        \n        // Left join using GroupJoin\n        var leftJoin = from c in customers\n                       join o in orders on c.Id equals o.CustomerId into customerOrders\n                       from co in customerOrders.DefaultIfEmpty()\n                       select new { c.Name, Amount = co?.Amount ?? 0 };\n        \n        Console.WriteLine(\"Left Join Results:\");\n        foreach (var item in leftJoin)\n            Console.WriteLine($\"  {item.Name}: ${item.Amount}\");\n    }\n}",
