    codeSolution: "using System;\nusing System.Collections.Generic;\nusing System.Linq;\n\nclass Student\n{\n    public string Name { get; set; }\n    public List<string> Courses { get; set; }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        List<Student> students = new List<Student>\n        {\n            new Student { Name = \"Alice\", Courses = new List<string> { \"Math\", \"Physics\" } },\n            new Student { Name = \"Bob\", Courses = new List<string> { \"Chemistry\", \"Biology\" } },\n            new Student { Name = \"Charlie\", Courses = new List<string> { \"Math\", \"Computer Science\" } }\n        };\n        \n        // Query syntax\n        var allCourses = from s in students\n                         from c in s.Courses\n                         select c;\n        \n        Console.WriteLine($\"All courses: {string.Join(\", \", allCourses)}\");\n        \n        // Distinct courses\n        var uniqueCourses = allCourses.Distinct();\n        Console.WriteLine($\"Unique courses: {string.Join(\", \", uniqueCourses)}\");\n        \n        // Method syntax\n        var allCoursesMethod = students.SelectMany(s => s.Courses);\n        Console.WriteLine($\"Method syntax: {string.Join(\", \", allCoursesMethod)}\");\n    }\n}",
