    topicId: "cs_linq",
    question: "Use LINQ Except, Intersect, Union for set operations.",
    mathSolution: "setA.Except(setB), setA.Intersect(setB), setA.Union(setB)",
    codeSolution: "using System;\nusing System.Linq;\n\nclass Program\n{\n    static void Main()\n    {\n        int[] setA = { 1, 2, 3, 4, 5 };\n        int[] setB = { 4, 5, 6, 7, 8 };\n        \n        var union = setA.Union(setB);\n        var intersect = setA.Intersect(setB);\n        var except = setA.Except(setB);\n        var symmetricExcept = setA.Union(setB).Except(setA.Intersect(setB));\n        \n        Console.WriteLine($\"Union: {string.Join(\", \", union)}\");\n        Console.WriteLine($\"Intersection: {string.Join(\", \", intersect)}\");\n        Console.WriteLine($\"Except (A - B): {string.Join(\", \", except)}\");\n        Console.WriteLine($\"Symmetric Except: {string.Join(\", \", symmetricExcept)}\");\n    }\n}",
    hint: "Union combines sets, Intersect finds common elements, Except finds differences.",
