    mathSolution: "numbers.Aggregate((a, b) => a + b)",
    codeSolution: "using System;\nusing System.Linq;\nusing System.Text;\n\nclass Program\n{\n    static void Main()\n    {\n        int[] numbers = { 1, 2, 3, 4, 5 };\n        \n        int sum = numbers.Aggregate((a, b) => a + b);\n        Console.WriteLine($\"Sum: {sum}\");\n        \n        int product = numbers.Aggregate((a, b) => a * b);\n        Console.WriteLine($\"Product: {product}\");\n        \n        // With seed\n        int sumWithSeed = numbers.Aggregate(10, (a, b) => a + b);\n        Console.WriteLine($\"Sum with seed 10: {sumWithSeed}\");\n        \n        // With result selector\n        string result = numbers.Aggregate(0, (sum, n) => sum + n, sum => $\"Total: {sum}\");\n        Console.WriteLine(result);\n        \n        // With StringBuilder\n        string[] words = { \"Hello\", \"World\", \"from\", \"LINQ\" };\n        string sentence = words.Aggregate(new StringBuilder(), \n            (sb, word) => sb.Append(word).Append(\" \"),\n            sb => sb.ToString().Trim());\n        Console.WriteLine($\"Sentence: {sentence}\");\n    }\n}",
    hint: "Aggregate combines all elements using a function, optionally with seed and result selector.",
