    question: "Use LINQ DefaultIfEmpty for handling empty collections.",
    mathSolution: "empty.DefaultIfEmpty(0)",
    codeSolution: "using System;\nusing System.Linq;\n\nclass Program\n{\n    static void Main()\n    {\n        int[] empty = new int[0];\n        int[] numbers = { 1, 2, 3 };\n        \n        var withDefault = empty.DefaultIfEmpty();\n        Console.WriteLine($\"Empty with default: {string.Join(\", \", withDefault)}\");\n        \n        var withCustomDefault = empty.DefaultIfEmpty(99);\n        Console.WriteLine($\"Empty with custom default: {string.Join(\", \", withCustomDefault)}\");\n        \n        var nonEmpty = numbers.DefaultIfEmpty(0);\n        Console.WriteLine($\"Non-empty with default: {string.Join(\", \", nonEmpty)}\");\n        \n        // Practical: Left join\n        var left = new[] { 1, 2, 3 };\n        var right = new[] { 1, 3 };\n        \n        var leftJoin = from l in left\n                       join r in right on l equals r into joined\n                       from j in joined.DefaultIfEmpty(-1)\n                       select new { Left = l, Right = j };\n        \n        foreach (var item in leftJoin)\n            Console.WriteLine($\"Left: {item.Left}, Right: {item.Right}\");\n    }\n}",
    hint: "DefaultIfEmpty provides a default value when the sequence is empty.",
