    mathSolution: "arrayList.Cast<int>()",
    codeSolution: "using System;\nusing System.Collections;\nusing System.Linq;\n\nclass Program\n{\n    static void Main()\n    {\n        ArrayList arrayList = new ArrayList { 1, 2, 3, 4, 5 };\n        \n        var numbers = arrayList.Cast<int>();\n        Console.WriteLine($\"Cast from ArrayList: {string.Join(\", \", numbers)}\");\n        \n        List<object> objectList = new List<object> { 10, 20, 30, 40, 50 };\n        var ints = objectList.Cast<int>();\n        Console.WriteLine($\"Cast from object list: {string.Join(\", \", ints)}\");\n        \n        // Cast with Where\n        var evens = objectList.Cast<int>().Where(n => n % 2 == 0);\n        Console.WriteLine($\"Evens: {string.Join(\", \", evens)}\");\n        \n        // Safety: OfType vs Cast\n        ArrayList mixed = new ArrayList { 1, \"two\", 3, \"four\", 5 };\n        \n        var safe = mixed.OfType<int>();\n        Console.WriteLine($\"OfType (safe): {string.Join(\", \", safe)}\");\n        \n        try\n        {\n            var unsafeCast = mixed.Cast<int>();\n            Console.WriteLine(string.Join(\", \", unsafeCast));\n        }\n        catch (InvalidCastException ex)\n        {\n            Console.WriteLine($\"Cast failed: {ex.Message}\");\n        }\n    }\n}",
