    codeSolution: "using System;\nusing System.Linq;\n\nclass Program\n{\n    static void Main()\n    {\n        var numbers = Enumerable.Range(1, 10);\n        Console.WriteLine($\"Range 1-10: {string.Join(\", \", numbers)}\");\n        \n        var repeated = Enumerable.Repeat(\"Hello\", 5);\n        Console.WriteLine($\"Repeated: {string.Join(\", \", repeated)}\");\n        \n        // Generate squares\n        var squares = Enumerable.Range(1, 10).Select(n => n * n);\n        Console.WriteLine($\"Squares: {string.Join(\", \", squares)}\");\n        \n        // Generate multiplication table\n        var table = Enumerable.Range(1, 5).SelectMany(i =>\n            Enumerable.Range(1, 5).Select(j => $\"{i} x {j} = {i * j}\"));\n        \n        Console.WriteLine(\"Multiplication Table:\");\n        foreach (var item in table.Take(10))\n            Console.WriteLine($\"  {item}\");\n        \n        // Generate step sequence\n        var steps = Enumerable.Range(0, 10).Select(n => n * 2);\n        Console.WriteLine($\"Steps of 2: {string.Join(\", \", steps)}\");\n    }\n}",
    hint: "Range generates integer sequences; Repeat generates repeated values.",
