    codeSolution: "using System;\nusing System.Collections.Generic;\n\nclass Program\n{\n    static void Main()\n    {\n        List<int> numbers = new List<int> { 1, 2, 3, 4, 5, 3, 6, 7, 3, 8 };\n        \n        Console.WriteLine($\"Original: {string.Join(\", \", numbers)}\");\n        \n        // Remove by value (first occurrence only)\n        numbers.Remove(3);\n        Console.WriteLine($\"After Remove(3): {string.Join(\", \", numbers)}\");\n        \n        // Remove by index\n        numbers.RemoveAt(2);\n        Console.WriteLine($\"After RemoveAt(2): {string.Join(\", \", numbers)}\");\n        \n        // Remove all elements matching condition\n        numbers.RemoveAll(x => x > 5);\n        Console.WriteLine($\"After RemoveAll(x > 5): {string.Join(\", \", numbers)}\");\n        \n        // Remove range\n        numbers.RemoveRange(1, 2);\n        Console.WriteLine($\"After RemoveRange(1,2): {string.Join(\", \", numbers)}\");\n    }\n}",
