    mathSolution: "Searching for elements in List.",
    codeSolution: "using System;\nusing System.Collections.Generic;\n\nclass Program\n{\n    static void Main()\n    {\n        List<string> names = new List<string> { \"Alice\", \"Bob\", \"Charlie\", \"Diana\" };\n        \n        // Contains - exact match\n        bool hasBob = names.Contains(\"Bob\");\n        bool hasJohn = names.Contains(\"John\");\n        \n        Console.WriteLine($\"Contains 'Bob': {hasBob}\");\n        Console.WriteLine($\"Contains 'John': {hasJohn}\");\n        \n        // Exists - with predicate\n        bool hasLongName = names.Exists(n => n.Length > 6);\n        bool hasStartA = names.Exists(n => n.StartsWith(\"A\"));\n        \n        Console.WriteLine($\"Exists name > 6 chars: {hasLongName}\");\n        Console.WriteLine($\"Exists name starting with 'A': {hasStartA}\");\n        \n        // TrueForAll - check if all match condition\n        bool allShort = names.TrueForAll(n => n.Length < 10);\n        Console.WriteLine($\"All names < 10 chars: {allShort}\");\n    }\n}",
