    question: "Find elements using Find(), FindAll(), FindIndex() methods.",
    mathSolution: "Searching and finding elements with predicates.",
    codeSolution: "using System;\nusing System.Collections.Generic;\n\nclass Program\n{\n    static void Main()\n    {\n        List<int> numbers = new List<int> { 10, 25, 33, 42, 55, 68, 72, 89, 94 };\n        \n        // Find first match\n        int firstEven = numbers.Find(n => n % 2 == 0);\n        Console.WriteLine($\"First even number: {firstEven}\");\n        \n        // Find last match\n        int lastOdd = numbers.FindLast(n => n % 2 != 0);\n        Console.WriteLine($\"Last odd number: {lastOdd}\");\n        \n        // Find all matches\n        List<int> multiplesOf3 = numbers.FindAll(n => n % 3 == 0);\n        Console.WriteLine($\"Multiples of 3: {string.Join(\", \", multiplesOf3)}\");\n        \n        // Find index\n        int indexOf55 = numbers.FindIndex(n => n == 55);\n        int lastIndexEven = numbers.FindLastIndex(n => n % 2 == 0);\n        \n        Console.WriteLine($\"Index of 55: {indexOf55}\");\n        Console.WriteLine($\"Last even index: {lastIndexEven}\");\n        \n        // Find all indices\n        List<int> evenIndices = new List<int>();\n        for (int i = 0; i < numbers.Count; i++)\n        {\n            if (numbers[i] % 2 == 0)\n                evenIndices.Add(i);\n        }\n        Console.WriteLine($\"Even number indices: {string.Join(\", \", evenIndices)}\");\n    }\n}",
    hint: "Find() returns first match, FindAll() returns all matches, FindIndex() returns position.",
