    id: "cs_mt_3",
    topicId: "cs_multithreading",
    question: "Use ThreadPool to execute background tasks.",
    mathSolution: "ThreadPool for efficient thread management.",
    codeSolution: "using System;\nusing System.Threading;\n\nclass Program\n{\n    static void Main()\n    {\n        Console.WriteLine($\"Main thread: {Thread.CurrentThread.ManagedThreadId}\");\n        Console.WriteLine($\"ThreadPool min threads: {ThreadPool.GetMinThreads(out int worker, out int io)}\");\n        Console.WriteLine($\"  Worker: {worker}, IO: {io}\");\n        \n        // Queue work items\n        for (int i = 1; i <= 5; i++)\n        {\n            int taskId = i;\n            ThreadPool.QueueUserWorkItem(state =>\n            {\n                Console.WriteLine($\"Task {taskId} started on thread {Thread.CurrentThread.ManagedThreadId}\");\n                Thread.Sleep(500);\n                Console.WriteLine($\"Task {taskId} completed\");\n            });\n        }\n        \n        Console.WriteLine(\"All tasks queued\");\n        Thread.Sleep(3000);\n        Console.WriteLine(\"Main thread ending\");\n    }\n}",
    hint: "Use ThreadPool.QueueUserWorkItem() for background tasks.",
